package com.flowledger.tax.controller; import com.flowledger.tax.dto.GstCalculationDtos.*; import com.flowledger.tax.service.GstCalculationService; import jakarta.validation.*; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/api/v1/tax") public class GstCalculationController{private final GstCalculationService s;public GstCalculationController(GstCalculationService s){this.s=s;}@PostMapping("/calculate")public Response calculate(@Valid @RequestBody Request r){return s.calculate(r);}}